                    <button class="clay-button" onclick="chooseAction(this)"><i class="fas fa-eye"></i> $44</button>
                    <button class="clay-button" onclick="chooseAction(this)"><i class="fas fa-walking"></i> $45</button>
                    <button class="clay-button" onclick="chooseAction(this)"><i class="fas fa-hand-paper"></i> $46</button>
                </div>
            </div>
        </div>
