    <script>
        function chooseAction(buttonElement) {
            // 克隆按钮节点以移除图标
            const tempNode = buttonElement.cloneNode(true);
            const icon = tempNode.querySelector('i');
            if (icon) {
                tempNode.removeChild(icon);
            }
            const actionText = tempNode.innerText.trim();

            const command = `/send ${actionText} | /trigger`;

            if (typeof triggerSlash === 'function') {
                // 显示提示信息，告知用户操作已执行
                triggerSlash(`/echo severity=info 已选择选项：“${actionText}”，正在生成后续剧情...`);
                // 执行发送和触发命令
                triggerSlash(command);
            } else {
                console.log("triggerSlash function not found. Command to execute: ", command);
                alert("交互功能未加载，请检查SillyTavern环境。");
            }
        }
    </script>

</body>
